import { useEffect, useState } from 'react';

// material-ui
import Grid from '@mui/material/Grid';
import Table from '@mui/material/Table';
import TableBody from '@mui/material/TableBody';
import TableCell from '@mui/material/TableCell';
import TableContainer from '@mui/material/TableContainer';
import TableHead from '@mui/material/TableHead';
import TableRow from '@mui/material/TableRow';
import Typography from '@mui/material/Typography';
import Chip from '@mui/material/Chip';
import CircularProgress from '@mui/material/CircularProgress';
import Box from '@mui/material/Box';
import Avatar from '@mui/material/Avatar';
import Button from '@mui/material/Button';
import Dialog from '@mui/material/Dialog';
import DialogTitle from '@mui/material/DialogTitle';
import DialogContent from '@mui/material/DialogContent';
import DialogActions from '@mui/material/DialogActions';
import TextField from '@mui/material/TextField';
import Select from '@mui/material/Select';
import MenuItem from '@mui/material/MenuItem';
import FormControl from '@mui/material/FormControl';
import InputLabel from '@mui/material/InputLabel';
import IconButton from '@mui/material/IconButton';

// ant design icons
import PlusOutlined from '@ant-design/icons/PlusOutlined';
import UploadOutlined from '@ant-design/icons/UploadOutlined';

// project imports
import MainCard from 'components/MainCard';
import axiosServices from 'utils/axios';

const DEFAULT_IMAGE = 'https://placehold.co/100x100?text=No+Image';

export default function ProductsPage() {
  const [products, setProducts] = useState([]);
  const [categories, setCategories] = useState([]);
  const [loading, setLoading] = useState(true);
  
  const [openModal, setOpenModal] = useState(false);
  const [formData, setFormData] = useState({
    name: '', basePrice: '', categoryId: '', imageUrl: ''
  });
  const [uploading, setUploading] = useState(false);

  useEffect(() => {
    fetchData();
  }, []);

  const fetchData = async () => {
    try {
      const [resProducts, resCategories] = await Promise.all([
        axiosServices.get('Products'),
        axiosServices.get('Categories')
      ]);
      setProducts(resProducts.data);
      setCategories(resCategories.data);
      setLoading(false);
    } catch (error) {
      console.error("Lỗi khi tải dữ liệu:", error);
      setLoading(false);
    }
  };

  const handleImageUpload = async (event) => {
    const file = event.target.files[0];
    if (!file) return;

    const formDataUpload = new FormData();
    formDataUpload.append('file', file);

    setUploading(true);
    try {
      const res = await axiosServices.post('Uploads/image', formDataUpload, {
        headers: { 'Content-Type': 'multipart/form-data' }
      });
      setFormData({ ...formData, imageUrl: res.data.url });
    } catch (error) {
        console.error(error);
      alert('Lỗi khi tải ảnh lên!');
    } finally {
      setUploading(false);
    }
  };

  const handleSaveProduct = async () => {
    if (!formData.name || !formData.basePrice || !formData.categoryId) {
      alert("Vui lòng nhập đủ Tên, Giá và Chọn danh mục!");
      return;
    }

    try {
      await axiosServices.post('Products', {
        vendorId: "00000000-0000-0000-0000-000000000000",
        categoryId: parseInt(formData.categoryId),
        name: formData.name,
        basePrice: parseFloat(formData.basePrice),
        imageUrl: formData.imageUrl
      });
      
      setOpenModal(false);
      setFormData({ name: '', basePrice: '', categoryId: '', imageUrl: '' });
      fetchData();
    } catch (error) {
        console.error(error);
      alert('Lỗi khi lưu sản phẩm!');
    }
  };

  return (
    <Grid container spacing={3}>
      <Grid size={12}>
        <MainCard 
          title="Danh sách sản phẩm"
          secondary={
            <Button variant="contained" startIcon={<PlusOutlined />} onClick={() => setOpenModal(true)}>
              Thêm sản phẩm
            </Button>
          }
        >
          {loading ? (
            <Box sx={{ display: 'flex', justifyContent: 'center', p: 3 }}><CircularProgress /></Box>
          ) : (
            <TableContainer>
              <Table sx={{ minWidth: 650 }}>
                <TableHead>
                  <TableRow>
                    <TableCell>STT</TableCell>
                    <TableCell>Hình ảnh</TableCell>
                    <TableCell>Tên sản phẩm</TableCell>
                    <TableCell>Danh mục</TableCell>
                    <TableCell align="right">Giá bán</TableCell>
                    <TableCell align="center">Trạng thái</TableCell>
                  </TableRow>
                </TableHead>
                <TableBody>
                  {products.length === 0 ? (
                    <TableRow>
                      <TableCell colSpan={6} align="center">
                        <Typography variant="subtitle1">Chưa có sản phẩm nào trong hệ thống.</Typography>
                      </TableCell>
                    </TableRow>
                  ) : (
                    products.map((row, index) => (
                      <TableRow key={row.id} hover>
                        <TableCell>{index + 1}</TableCell>
                        <TableCell>
                          <Avatar src={row.imageUrl || DEFAULT_IMAGE} alt={row.name} variant="rounded" sx={{ width: 50, height: 50 }} />
                        </TableCell>
                        <TableCell><Typography variant="subtitle2">{row.name}</Typography></TableCell>
                        <TableCell><Typography variant="body2">{row.categoryName}</Typography></TableCell>
                        <TableCell align="right">{new Intl.NumberFormat('vi-VN', { style: 'currency', currency: 'VND' }).format(row.basePrice)}</TableCell>
                        <TableCell align="center">
                          <Chip label={row.status === 'Active' ? 'Đang bán' : 'Ngừng bán'} color={row.status === 'Active' ? 'success' : 'default'} size="small" />
                        </TableCell>
                      </TableRow>
                    ))
                  )}
                </TableBody>
              </Table>
            </TableContainer>
          )}
        </MainCard>
      </Grid>

      {/* --- MODAL THÊM SẢN PHẨM --- */}
      <Dialog open={openModal} onClose={() => setOpenModal(false)} maxWidth="sm" fullWidth>
        <DialogTitle>Thêm Sản Phẩm Mới</DialogTitle>
        <DialogContent dividers>
          <Grid container spacing={2}>
            
            <Grid size={12} sx={{ display: 'flex', flexDirection: 'column', alignItems: 'center', mb: 2, mt: 2 }}>
              <Avatar src={formData.imageUrl || DEFAULT_IMAGE} variant="rounded" sx={{ width: 100, height: 100, mb: 2 }} />
              <Button variant="outlined" component="label" startIcon={uploading ? <CircularProgress size={20} /> : <UploadOutlined />} disabled={uploading}>
                {uploading ? "Đang tải..." : "Tải ảnh lên"}
                <input type="file" hidden accept="image/*" onChange={handleImageUpload} />
              </Button>
            </Grid>

            <Grid size={12}>
              <TextField fullWidth label="Tên sản phẩm" value={formData.name} onChange={(e) => setFormData({ ...formData, name: e.target.value })} />
            </Grid>
            <Grid size={6}>
              <TextField fullWidth type="number" label="Giá bán (VND)" value={formData.basePrice} onChange={(e) => setFormData({ ...formData, basePrice: e.target.value })} />
            </Grid>
            <Grid size={6}>
              <FormControl fullWidth>
                <InputLabel>Danh mục</InputLabel>
                <Select label="Danh mục" value={formData.categoryId} onChange={(e) => setFormData({ ...formData, categoryId: e.target.value })}>
                  {categories.map((cat) => (
                    <MenuItem key={cat.id} value={cat.id}>{cat.name}</MenuItem>
                  ))}
                </Select>
              </FormControl>
            </Grid>
          </Grid>
        </DialogContent>
        <DialogActions>
          <Button onClick={() => setOpenModal(false)} color="error">Hủy</Button>
          <Button onClick={handleSaveProduct} variant="contained" color="primary">Lưu sản phẩm</Button>
        </DialogActions>
      </Dialog>
    </Grid>
  );
}